DROP TABLE IF EXISTS `entrada`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `entrada` (
  `entrada_id` int NOT NULL AUTO_INCREMENT,
  `partido_id` int NOT NULL,
  `usuario_id` int DEFAULT NULL,
  `estado` enum('disponible','reservada','pagada','transferida','cancelada') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'disponible',
  `asiento` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `seccion` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `precio` decimal(10,2) NOT NULL DEFAULT '0.00',
  `codigo_qr` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`entrada_id`),
  KEY `idx_partido` (`partido_id`),
  KEY `idx_usuario` (`usuario_id`),
  CONSTRAINT `entrada_ibfk_1` FOREIGN KEY (`partido_id`) REFERENCES `partido` (`partido_id`),
  CONSTRAINT `entrada_ibfk_2` FOREIGN KEY (`usuario_id`) REFERENCES `usuario` (`usuario_id`)
) ENGINE=InnoDB AUTO_INCREMENT=1441 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
