  `partido_id` int DEFAULT NULL,
  `leida` tinyint(1) DEFAULT '0',
  `fecha_envio` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `fecha_lectura` datetime DEFAULT NULL,
  PRIMARY KEY (`notificacion_id`),
